class Solution:
    def subStrHash(self, s, power, modulo, k, hashValue):
        n = len(s)
        def val(c):
            return ord(c) - ord('a') + 1
        for i in range(n - k + 1):
            h = 0
            p_pow = 1
            for t in range(k):
                h = (h + val(s[i + t]) * p_pow) % modulo
                p_pow = (p_pow * power) % modulo
            if h == hashValue:
                return s[i:i + k]
        return ''

