var subStrHash = function(s, power, modulo, k, hashValue) {
    const n = s.length;
    const P = BigInt(power);
    const M = BigInt(modulo);
    const HV = BigInt(hashValue);
    const val = (c) => BigInt(c.charCodeAt(0) - 96);
    let h = 0n;
    for (let t = k - 1; t >= 0; t--) {
        h = (h * P + val(s[n - k + t])) % M;
    }
    let pk = 1n;
    for (let i = 0; i < k; i++) pk = (pk * P) % M;
    let ans = (h === HV) ? n - k : -1;
    for (let i = n - k - 1; i >= 0; i--) {
        let diff = (h * P + val(s[i]) - val(s[i + k]) * pk) % M;
        if (diff < 0n) diff += M;
        h = diff;
        if (h === HV) ans = i;
    }
    return s.substring(ans, ans + k);
};
